80	        )
81	        .init();
82	
83	    tracing::info!("All Together Now — PGM server starting");
84	
85	    let config_path = std::env::args()
86	        .nth(1)
87	        .unwrap_or_else(|| DEFAULT_CONFIG_PATH.to_string());
88	    let config_path = PathBuf::from(&config_path);
89	
90	    let base_dir = config_path
91	        .parent()
92	        .unwrap_or_else(|| std::path::Path::new("."))
93	        .to_path_buf();
94	
95	    let project_config = load_project_config(&config_path).unwrap_or_else(|e| {
96	        tracing::error!("Failed to load {}: {e}", config_path.display());
97	        tracing::info!("Starting with no agents — create agents.toml to configure");
98	        atn_core::config::ProjectConfig {
