53	        .view-tab { padding: 4px 12px; border: 1px solid #0f3460; border-radius: 4px; background: transparent; color: #888; cursor: pointer; font-size: 12px; }
54	        .view-tab.active { background: #0f3460; color: #e0e0e0; }
55	        .view-tab:hover { color: #e0e0e0; }
56	
57	        /* Wiki browser */
58	        .wiki-container { flex: 1; display: flex; min-height: 0; overflow: hidden; }
59	        .wiki-sidebar { width: 220px; border-right: 1px solid #0f3460; overflow-y: auto; padding: 8px 0; flex-shrink: 0; }
60	        .wiki-sidebar h3 { font-size: 12px; color: #888; padding: 4px 12px; text-transform: uppercase; letter-spacing: 0.5px; }
61	        .wiki-page-item { padding: 6px 12px; cursor: pointer; font-size: 13px; color: #c9d1d9; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
62	        .wiki-page-item:hover { background: #1e3a5f; }
63	        .wiki-page-item.active { background: #0f3460; color: #e94560; }
64	        .wiki-main { flex: 1; display: flex; flex-direction: column; min-width: 0; overflow: hidden; }
65	        .wiki-toolbar { padding: 8px 12px; border-bottom: 1px solid #0f3460; display: flex; align-items: center; gap: 8px; flex-shrink: 0; }
66	        .wiki-toolbar .page-title { font-size: 14px; font-weight: 600; color: #c9d1d9; flex: 1; }
67	        .wiki-toolbar button { padding: 4px 10px; border: 1px solid #0f3460; border-radius: 4px; background: transparent; color: #c9d1d9; cursor: pointer; font-size: 12px; }
68	        .wiki-toolbar button:hover { background: #0f3460; }
69	        .wiki-toolbar button.btn-save { background: #4ecca3; color: #1a1a2e; border-color: #4ecca3; }
70	        .wiki-toolbar button.btn-save:hover { background: #3db892; }
71	        .wiki-content { flex: 1; overflow-y: auto; padding: 16px 20px; }
72	        .wiki-content h1, .wiki-content h2, .wiki-content h3 { color: #c9d1d9; margin: 16px 0 8px; }
73	        .wiki-content h1 { font-size: 22px; border-bottom: 1px solid #0f3460; padding-bottom: 6px; }
74	        .wiki-content h2 { font-size: 18px; }
75	        .wiki-content p { margin: 8px 0; line-height: 1.6; }
76	        .wiki-content ul, .wiki-content ol { margin: 8px 0; padding-left: 24px; }
77	        .wiki-content a.wiki-link { color: #4ecca3; text-decoration: none; cursor: pointer; }
78	        .wiki-content a.wiki-link:hover { text-decoration: underline; }
79	        .wiki-edit-area { flex: 1; display: flex; flex-direction: column; padding: 8px; min-height: 0; }
80	        .wiki-edit-area textarea { flex: 1; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-family: 'JetBrains Mono', monospace; font-size: 13px; padding: 12px; resize: none; outline: none; }
81	        .wiki-edit-area textarea:focus { border-color: #e94560; }
82	        .wiki-conflict { background: #7f1d1d; border: 1px solid #f87171; border-radius: 4px; padding: 10px 14px; margin: 8px; color: #fca5a5; font-size: 13px; }
83	        .wiki-new-page { display: flex; gap: 6px; padding: 8px 12px; border-top: 1px solid #0f3460; }
84	        .wiki-new-page input { flex: 1; padding: 4px 8px; background: #0d1117; border: 1px solid #0f3460; border-radius: 4px; color: #e0e0e0; font-size: 12px; outline: none; }
85	        .wiki-new-page button { padding: 4px 10px; background: #4ecca3; color: #1a1a2e; border: none; border-radius: 4px; cursor: pointer; font-size: 12px; }
86	    </style>
87	</head>
88	<body>
89	    <header>
90	        <h1>All Together Now</h1>
91	        <span class="agent-count" id="agent-count"></span>
92	        <div class="view-tabs">
93	            <button class="view-tab active" id="tab-agents" onclick="switchView('agents')">Agents</button>
94	            <button class="view-tab" id="tab-wiki" onclick="switchView('wiki')">Wiki</button>
95	        </div>
96	    </header>
97	    <div class="dashboard" id="dashboard"></div>
98	    <div class="wiki-container" id="wiki-view" style="display:none;">
99	        <div class="wiki-sidebar">
100	            <h3>Pages</h3>
101	            <div id="wiki-page-list"></div>
102	            <div class="wiki-new-page">
103	                <input type="text" id="wiki-new-title" placeholder="New page title...">
104	                <button onclick="wikiNewPage()">+</button>
105	            </div>
106	        </div>
107	        <div class="wiki-main">
108	            <div class="wiki-toolbar">
109	                <span class="page-title" id="wiki-page-title">Select a page</span>
110	                <button id="wiki-edit-btn" onclick="wikiToggleEdit()" style="display:none;">Edit</button>
111	                <button id="wiki-save-btn" class="btn-save" onclick="wikiSave()" style="display:none;">Save</button>
112	                <button id="wiki-cancel-btn" onclick="wikiCancelEdit()" style="display:none;">Cancel</button>
113	            </div>
114	            <div id="wiki-conflict" class="wiki-conflict" style="display:none;"></div>
115	            <div class="wiki-content" id="wiki-content"></div>
116	            <div class="wiki-edit-area" id="wiki-edit-area" style="display:none;">
117	                <textarea id="wiki-editor"></textarea>
118	            </div>
119	        </div>
120	    </div>
121	
122	    <script src="https://cdn.jsdelivr.net/npm/@xterm/xterm@5.5.0/lib/xterm.min.js"></script>
123	    <script src="https://cdn.jsdelivr.net/npm/@xterm/addon-fit@0.10.0/lib/addon-fit.min.js"></script>
124	    <script>
125	        const API_BASE = '';
126	        const agents = new Map(); // id -> { term, fitAddon, evtSource, panel }
127	
128	        const STATE_LABELS = {
129	            starting: 'Starting',
130	            running: 'Running',
131	            idle: 'Idle',
132	            awaiting_human_input: 'Awaiting Input',
133	            busy: 'Busy',
134	            blocked: 'Blocked',
135	            completed_task: 'Completed',
136	            error: 'Error',
137	            disconnected: 'Disconnected',
138	        };
139	
140	        function stateKey(stateObj) {
141	            if (typeof stateObj === 'string') return stateObj;
142	            if (stateObj && stateObj.state) return stateObj.state;
143	            return 'starting';
144	        }
145	
146	        function stateLabel(stateObj) {
147	            const key = stateKey(stateObj);
148	            return STATE_LABELS[key] || key;
149	        }
150	
151	        function createAgentPanel(agent) {
152	            const panel = document.createElement('div');
153	            panel.className = 'agent-panel';
154	            panel.id = `panel-${agent.id}`;
155	
156	            const sk = stateKey(agent.state);
157	
158	            panel.innerHTML = `
159	                <div class="agent-header">
160	                    <span class="agent-name">${agent.name}</span>
161	                    <span class="agent-role">${agent.role}</span>
162	                    <span class="spacer"></span>
163	                    <span class="conn-dot disconnected" id="conn-${agent.id}"></span>
164	                    <span class="state-badge state-${sk}" id="badge-${agent.id}">${stateLabel(agent.state)}</span>
165	                </div>
166	                <div class="agent-terminal" id="term-${agent.id}"></div>
167	                <div class="agent-controls">
168	                    <input type="text" id="input-${agent.id}" placeholder="Command for ${agent.name}...">
169	                    <button class="btn-send" data-agent="${agent.id}">Send</button>
170	                    <button class="btn-ctrl-c" data-agent="${agent.id}">^C</button>
171	                </div>
172	            `;
173	            return panel;
174	        }
175	
176	        function initTerminal(agentId) {
177	            const term = new Terminal({
178	                cursorBlink: true,
179	                fontSize: 13,
180	                fontFamily: "'JetBrains Mono', 'Fira Code', 'Cascadia Code', monospace",
181	                theme: {
182	                    background: '#0d1117',
183	                    foreground: '#c9d1d9',
184	                    cursor: '#e94560',
185	                    selectionBackground: '#264f78',
186	                },
187	            });
188	            const fitAddon = new FitAddon.FitAddon();
189	            term.loadAddon(fitAddon);
190	
191	            const container = document.getElementById(`term-${agentId}`);
192	            term.open(container);
193	            fitAddon.fit();
194	            return { term, fitAddon };
195	        }
196	
197	        function connectSSE(agentId) {
198	            const connDot = document.getElementById(`conn-${agentId}`);
199	            const evtSource = new EventSource(`${API_BASE}/api/agents/${agentId}/sse`);
200	            const agent = agents.get(agentId);
201	
202	            evtSource.onopen = () => {
203	                connDot.className = 'conn-dot connected';
204	            };
205	
206	            evtSource.onmessage = (event) => {
207	                const bytes = Uint8Array.from(atob(event.data), c => c.charCodeAt(0));
208	                agent.term.write(bytes);
209	            };
210	
211	            evtSource.onerror = () => {
212	                connDot.className = 'conn-dot disconnected';
213	                evtSource.close();
214	                setTimeout(() => connectSSE(agentId), 2000);
215	            };
216	
217	            agent.evtSource = evtSource;
218	        }
219	
220	        function setupControls(agentId) {
221	            const input = document.getElementById(`input-${agentId}`);
222	            const panel = document.getElementById(`panel-${agentId}`);
223	            const sendBtn = panel.querySelector('.btn-send');
224	            const ctrlcBtn = panel.querySelector('.btn-ctrl-c');
225	
226	            function doSend() {
227	                const text = input.value;
228	                if (text) {
229	                    fetch(`${API_BASE}/api/agents/${agentId}/input`, {
230	                        method: 'POST',
231	                        headers: { 'Content-Type': 'application/json' },
232	                        body: JSON.stringify({ text }),
233	                    });
234	                    input.value = '';
235	                }
236	                input.focus();
237	            }
238	
239	            sendBtn.addEventListener('click', doSend);
240	            input.addEventListener('keydown', (e) => {
241	                if (e.key === 'Enter') doSend();
242	            });
243	
244	            ctrlcBtn.addEventListener('click', () => {
245	                fetch(`${API_BASE}/api/agents/${agentId}/ctrl-c`, { method: 'POST' });
246	                input.focus();
247	            });
248	        }
249	
250	        // Poll agent states every 2 seconds
251	        async function pollStates() {
252	            try {
253	                const res = await fetch(`${API_BASE}/api/agents`);
254	                if (!res.ok) return;
255	                const list = await res.json();
256	                for (const agent of list) {
257	                    const badge = document.getElementById(`badge-${agent.id}`);
258	                    if (badge) {
259	                        const sk = stateKey(agent.state);
260	                        badge.className = `state-badge state-${sk}`;
261	                        badge.textContent = stateLabel(agent.state);
262	                    }
263	                }
264	            } catch (_) { /* ignore */ }
265	        }
266	
267	        async function init() {
268	            const res = await fetch(`${API_BASE}/api/agents`);
269	            const agentList = await res.json();
270	
271	            const dashboard = document.getElementById('dashboard');
272	            const count = agentList.length;
273	            document.getElementById('agent-count').textContent = `${count} agent${count !== 1 ? 's' : ''}`;
274	
275	            // Choose grid columns based on agent count
276	            if (count <= 1) dashboard.className = 'dashboard cols-1';
277	            else if (count <= 2) dashboard.className = 'dashboard cols-2';
278	            else dashboard.className = 'dashboard cols-3';
279	
280	            for (const agent of agentList) {
281	                const panel = createAgentPanel(agent);
282	                dashboard.appendChild(panel);
283	
284	                const { term, fitAddon } = initTerminal(agent.id);
285	                agents.set(agent.id, { term, fitAddon, panel, evtSource: null });
286	
287	                connectSSE(agent.id);
288	                setupControls(agent.id);
289	            }
290	
291	            // Handle resize
292	            const fitAll = () => agents.forEach(a => a.fitAddon.fit());
293	            window.addEventListener('resize', fitAll);
294	            new ResizeObserver(fitAll).observe(dashboard);
295	
296	            // Poll states
297	            setInterval(pollStates, 2000);
298	        }
299	
300	        init();
301	
302	        // ── View switching ─────────────────────────────────
303	        function switchView(view) {
304	            document.getElementById('dashboard').style.display = view === 'agents' ? '' : 'none';
305	            document.getElementById('wiki-view').style.display = view === 'wiki' ? '' : 'none';
306	            document.getElementById('tab-agents').className = 'view-tab' + (view === 'agents' ? ' active' : '');
307	            document.getElementById('tab-wiki').className = 'view-tab' + (view === 'wiki' ? ' active' : '');
308	            if (view === 'wiki') wikiLoadPageList();
309	        }
310	
311	        // ── Wiki state ─────────────────────────────────────
312	        let wikiCurrentPage = null;
313	        let wikiCurrentEtag = null;
314	        let wikiEditing = false;
315	
316	        async function wikiLoadPageList() {
317	            try {
318	                const res = await fetch(`${API_BASE}/api/wiki`);
319	                const pages = await res.json();
320	                const list = document.getElementById('wiki-page-list');
321	                list.innerHTML = '';
322	                for (const title of pages) {
323	                    const item = document.createElement('div');
324	                    item.className = 'wiki-page-item' + (title === wikiCurrentPage ? ' active' : '');
325	                    item.textContent = title.replace(/__/g, '/');
326	                    item.onclick = () => wikiOpenPage(title);
327	                    list.appendChild(item);
328	                }
329	            } catch (_) {}
330	        }
331	
332	        async function wikiOpenPage(title) {
333	            wikiEditing = false;
334	            try {
335	                const res = await fetch(`${API_BASE}/api/wiki/${encodeURIComponent(title)}`);
336	                if (!res.ok) return;
337	                const data = await res.json();
338	                wikiCurrentPage = title;
339	                wikiCurrentEtag = res.headers.get('ETag');
340	
341	                document.getElementById('wiki-page-title').textContent = data.title;
342	                document.getElementById('wiki-content').innerHTML = data.html;
343	                document.getElementById('wiki-content').style.display = '';
344	                document.getElementById('wiki-edit-area').style.display = 'none';
345	                document.getElementById('wiki-edit-btn').style.display = '';
346	                document.getElementById('wiki-save-btn').style.display = 'none';
347	                document.getElementById('wiki-cancel-btn').style.display = 'none';
348	                document.getElementById('wiki-conflict').style.display = 'none';
349	                document.getElementById('wiki-editor').value = data.content;
350	
351	                // Wire up wiki-link clicks
352	                document.querySelectorAll('#wiki-content a.wiki-link').forEach(a => {
353	                    a.addEventListener('click', (e) => {
354	                        e.preventDefault();
355	                        const target = a.getAttribute('data-wiki-link');
356	                        if (target) wikiOpenPage(target);
357	                    });
358	                });
359	
360	                wikiLoadPageList();
361	            } catch (_) {}
362	        }
363	
364	        function wikiToggleEdit() {
365	            wikiEditing = true;
366	            document.getElementById('wiki-content').style.display = 'none';
367	            document.getElementById('wiki-edit-area').style.display = 'flex';
368	            document.getElementById('wiki-edit-btn').style.display = 'none';
369	            document.getElementById('wiki-save-btn').style.display = '';
370	            document.getElementById('wiki-cancel-btn').style.display = '';
371	        }
372	
373	        function wikiCancelEdit() {
374	            wikiEditing = false;
375	            document.getElementById('wiki-content').style.display = '';
376	            document.getElementById('wiki-edit-area').style.display = 'none';
377	            document.getElementById('wiki-edit-btn').style.display = '';
378	            document.getElementById('wiki-save-btn').style.display = 'none';
379	            document.getElementById('wiki-cancel-btn').style.display = 'none';
380	            document.getElementById('wiki-conflict').style.display = 'none';
381	        }
382	
383	        async function wikiSave() {
384	            if (!wikiCurrentPage) return;
385	            const content = document.getElementById('wiki-editor').value;
386	            const headers = { 'Content-Type': 'application/json' };
387	            if (wikiCurrentEtag) headers['If-Match'] = wikiCurrentEtag;
388	
389	            try {
390	                const res = await fetch(`${API_BASE}/api/wiki/${encodeURIComponent(wikiCurrentPage)}`, {
391	                    method: 'PUT',
392	                    headers,
393	                    body: JSON.stringify({ content }),
394	                });
395	                if (res.status === 409) {
396	                    const data = await res.json();
397	                    document.getElementById('wiki-conflict').textContent =
398	                        `Conflict: page was modified by another user. Current version shown below. Your edits are preserved in the editor.`;
399	                    document.getElementById('wiki-conflict').style.display = '';
400	                    wikiCurrentEtag = data.current_etag;
401	                    return;
402	                }
403	                if (res.ok) {
404	                    wikiCurrentEtag = res.headers.get('ETag');
405	                    wikiOpenPage(wikiCurrentPage);
406	                }
407	            } catch (_) {}
408	        }
409	
410	        async function wikiNewPage() {
411	            const input = document.getElementById('wiki-new-title');
412	            const title = input.value.trim();
413	            if (!title) return;
414	
415	            try {
416	                const res = await fetch(`${API_BASE}/api/wiki/${encodeURIComponent(title)}`, {
417	                    method: 'PUT',
418	                    headers: { 'Content-Type': 'application/json' },
419	                    body: JSON.stringify({ content: `# ${title}\n\n` }),
420	                });
421	                if (res.ok || res.status === 201) {
422	                    input.value = '';
423	                    wikiOpenPage(title);
424	                }
425	            } catch (_) {}
426	        }
427	    </script>
