1	use std::path::PathBuf;
2	use std::sync::Arc;
3	
4	use portable_pty::{native_pty_system, CommandBuilder, MasterPty, PtySize};
5	use tokio::sync::{broadcast, mpsc, RwLock};
6	
7	use atn_core::agent::{AgentConfig, AgentId, AgentState};
8	use atn_core::error::{AtnError, Result};
9	use atn_core::event::{InputEvent, OutputSignal};
10	
11	use crate::reader::spawn_reader_task;
12	use crate::state_tracker::spawn_state_tracker;
13	use crate::transcript::TranscriptWriter;
14	use crate::writer::spawn_writer_task;
15	
16	const PTY_ROWS: u16 = 40;
17	const PTY_COLS: u16 = 120;
18	const OUTPUT_CHANNEL_CAPACITY: usize = 256;
19	const INPUT_CHANNEL_CAPACITY: usize = 64;
20	
21	/// A managed PTY session for one agent.
22	pub struct PtySession {
23	    agent_id: AgentId,
24	    agent_name: String,
25	    agent_role: String,
26	    child: Box<dyn portable_pty::Child + Send>,
27	    input_tx: mpsc::Sender<InputEvent>,
28	    output_tx: broadcast::Sender<OutputSignal>,
29	    state: Arc<RwLock<AgentState>>,
30	    _master: Box<dyn MasterPty + Send>,
31	    _reader_handle: tokio::task::JoinHandle<()>,
32	    _writer_handle: tokio::task::JoinHandle<()>,
33	    _transcript_handle: Option<tokio::task::JoinHandle<()>>,
34	    _state_tracker_handle: tokio::task::JoinHandle<()>,
35	}
36	
37	impl PtySession {
38	    /// Spawn a new PTY session for the given agent configuration.
39	    ///
40	    /// If `log_dir` is provided, transcript and event logs are written to
41	    /// `{log_dir}/{agent_id}/`.
42	    pub async fn spawn(config: &AgentConfig, log_dir: Option<PathBuf>) -> Result<Self> {
43	        let pty_system = native_pty_system();
44	
45	        let pair = pty_system
46	            .openpty(PtySize {
47	                rows: PTY_ROWS,
48	                cols: PTY_COLS,
49	                pixel_width: 0,
50	                pixel_height: 0,
51	            })
52	            .map_err(|e| AtnError::Pty(e.to_string()))?;
53	
54	        let mut cmd = CommandBuilder::new("bash");
55	        cmd.cwd(&config.repo_path);
56	
57	        let child = pair
58	            .slave
59	            .spawn_command(cmd)
60	            .map_err(|e| AtnError::Pty(e.to_string()))?;
61	
62	        // Drop slave — we only interact via the master side.
63	        drop(pair.slave);
64	
65	        let reader = pair
66	            .master
67	            .try_clone_reader()
68	            .map_err(|e| AtnError::Pty(e.to_string()))?;
69	
70	        let writer = pair
71	            .master
72	            .take_writer()
73	            .map_err(|e| AtnError::Pty(e.to_string()))?;
74	
75	        let (output_tx, _) = broadcast::channel(OUTPUT_CHANNEL_CAPACITY);
76	        let (input_tx, input_rx) = mpsc::channel(INPUT_CHANNEL_CAPACITY);
77	        let state = Arc::new(RwLock::new(AgentState::Starting));
78	
79	        let reader_handle = spawn_reader_task(reader, output_tx.clone());
80	        let writer_handle = spawn_writer_task(writer, input_rx);
81	
82	        // Optionally start transcript logging.
83	        let transcript_handle = if let Some(dir) = log_dir {
84	            let agent_dir = dir.join(&config.id.0);
85	            let tw = TranscriptWriter::new(&agent_dir)?;
86	            let rx = output_tx.subscribe();
87	            Some(tw.spawn(rx))
88	        } else {
89	            None
90	        };
91	
92	        // Start the state tracker.
93	        let state_tracker_rx = output_tx.subscribe();
94	        let state_tracker_handle = spawn_state_tracker(state_tracker_rx, state.clone());
95	
96	        // Inject setup commands.
97	        let setup_tx = input_tx.clone();
98	        let setup_commands = config.setup_commands.clone();
99	        let launch = config.launch_command.clone();
100	        let state_clone = state.clone();
101	        tokio::spawn(async move {
102	            // Set a known prompt for the outer shell.
103	            let _ = setup_tx
104	                .send(InputEvent::CoordinatorCommand {
105	                    command: r#"export PS1="__ATN_READY__> ""#.to_string(),
106	                })
107	                .await;
108	
109	            for cmd in &setup_commands {
110	                let _ = setup_tx
111	                    .send(InputEvent::CoordinatorCommand {
112	                        command: cmd.clone(),
113	                    })
114	                    .await;
115	            }
116	
117	            if !launch.is_empty() {
118	                let _ = setup_tx
119	                    .send(InputEvent::CoordinatorCommand {
120	                        command: launch,
121	                    })
122	                    .await;
123	            }
124	
125	            let mut s = state_clone.write().await;
126	            *s = AgentState::Running;
127	        });
128	
129	        Ok(Self {
130	            agent_id: config.id.clone(),
131	            agent_name: config.name.clone(),
132	            agent_role: format!("{:?}", config.role).to_lowercase(),
133	            child,
134	            input_tx,
135	            output_tx,
136	            state,
137	            _master: pair.master,
138	            _reader_handle: reader_handle,
139	            _writer_handle: writer_handle,
140	            _transcript_handle: transcript_handle,
141	            _state_tracker_handle: state_tracker_handle,
142	        })
143	    }
144	
145	    /// The agent ID for this session.
146	    pub fn agent_id(&self) -> &AgentId {
147	        &self.agent_id
148	    }
149	
150	    /// The agent's display name.
151	    pub fn name(&self) -> &str {
152	        &self.agent_name
153	    }
154	
155	    /// The agent's role as a lowercase string.
156	    pub fn role(&self) -> &str {
157	        &self.agent_role
158	    }
159	
160	    /// Get a clone of the input sender for this session.
161	    pub fn input_sender(&self) -> mpsc::Sender<InputEvent> {
